        .nav-link-icon { font-size: 12px; opacity: 0.7; }

        /* Ask button — highlighted */
        .nav-link-ask {
          color: #00ffc8;
          border-color: rgba(0,255,200,0.35);
          background: rgba(0,255,200,0.04);
