          padding: 6px 10px; cursor: pointer;
          font-family: 'Share Tech Mono', monospace;
          font-size: 12px;
          transition: color 0.2s, border-color 0.2s;
        }
        .menu-toggle:hover { color: #00ffc8; border-color: rgba(0,255,200,0.5); }

        @media (max-width: 700px) {
          .menu-toggle { display: flex; align-items: center; gap: 6px; }
          .nav-links { display: none; }
          .nav-links.open {
            display: flex; flex-direction: column; align-items: stretch;
            position: absolute; top: 100%; left: 0; right: 0;
            background: rgba(2,10,18,0.98);
            border-bottom: 1px solid rgba(0,255,200,0.12);
            padding: 12px 16px;
            gap: 6px;
            backdrop-filter: blur(20px);
          }
          .hdr-inner { position: relative; flex-wrap: wrap; height: auto; padding: 12px 16px; }
          .search-wrap { order: 3; max-width: 100%; flex: 1 1 100%; }
          .nav-divider { display: none; }
        }
      `}</style>

      <header className={`hdr ${mounted ? "on" : ""} ${scrolled ? "scrolled" : ""}`}>
        <div className="hdr-topline" />
        <div className="hdr-inner">
          <Link to="/" className="logo">
            Stack<span>It</span>
          </Link>

          <div className="search-wrap">
            <form className="search-form" onSubmit={handleSearch}>
              <span className="search-icon">⌕</span>
              <input
                ref={inputRef}
                className="search-input"
                type="text"
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                onFocus={() => setFocused(true)}
                onBlur={() => setFocused(false)}
                placeholder="Search questions, tags, users..."
                autoComplete="off"
              />
              <button type="submit" className="search-btn" aria-label="Search">▶</button>
            </form>
          </div>

          <div className="nav-divider" />

          <button
            className="menu-toggle"
            onClick={() => setMenuOpen((v) => !v)}
            aria-label="Toggle menu"
          >
            <span>{menuOpen ? "✕" : "≡"}</span>
            <span>MENU</span>
          </button>

          <nav className={`nav-links ${menuOpen ? "open" : ""}`}>
            {token ? (
              <>
                <div className="status-dot" title="Authenticated" />
                <Link to="/ask" className="nav-link nav-link-ask">
                  <span className="nav-link-icon">+</span>
                  Ask
                </Link>
                <Link to="/users/me" className="nav-link">
                  <span className="nav-link-icon">◈</span>
                  Profile
                </Link>
                <button className="nav-link nav-link-logout" onClick={logout}>
                  <span className="nav-link-icon">⏻</span>
                  Logout
                </button>
              </>
            ) : (
              <Link to="/login" className="nav-link nav-link-login">
                Authenticate
              </Link>
            )}
          </nav>
        </div>
      </header>
    </>
  );
}
